// MARK: - IoT Device Discovery & Communication

class IoTDeviceManager {
    
    static let shared = IoTDeviceManager()
    private let httpClient = HTTPClient.shared
    
    private init() {}
    
    /// Scan a range of local IP addresses for IoT devices
    func scanLocalNetwork(
        subnet: String = "192.168.1",
        port: Int = 80,
        startHost: Int = 1,
        endHost: Int = 254
    ) async -> [DiscoveredDevice] {
        var discoveredDevices: [DiscoveredDevice] = []
        let lock = NSLock()
        
        await withTaskGroup(of: DiscoveredDevice?.self) { group in
            for hostNumber in startHost...endHost {
                group.addTask {
                    let ipAddress = "\(subnet).\(hostNumber)"
                    let environment = APIEnvironment.localDevice(ipAddress: ipAddress, port: port)
                    
                    do {
                        let response = try await self.httpClient.get(
                            environment: environment,
                            path: "/info",
                            responseType: DeviceInfo.self
                        )
                        return DiscoveredDevice(
                            ipAddress: ipAddress,
                            port: port,
                            info: response.data
                        )
                    } catch {
                        // Device not found at this IP
                        return nil
                    }
                }
            }
            
            for await result in group {
                if let device = result {
                    lock.lock()
                    discoveredDevices.append(device)
                    lock.unlock()
                }
            }
        }
        
        return discoveredDevices
    }
    
    /// Send a command to a local IoT device
    func sendCommand(
        to ipAddress: String,
        port: Int? = nil,
        command: DeviceCommand
    ) async throws -> DeviceCommandResponse {
        let environment = APIEnvironment.localDevice(ipAddress: ipAddress, port: port)
        let response = try await httpClient.post(
            environment: environment,
            path: "/command",
            body: command,
            responseType: DeviceCommandResponse.self
        )
        return response.data
    }
    
    /// Get device status
    func getDeviceStatus(ipAddress: String, port: Int? = nil) async throws -> DeviceStatus {
        let environment = APIEnvironment.localDevice(ipAddress: ipAddress, port: port)
        let response = try await httpClient.get(
            environment: environment,
            path: "/status",
            responseType: DeviceStatus.self
        )
        return response.data
    }
    
    /// Update device firmware
    func updateFirmware(
        ipAddress: String,
        port: Int? = nil,
        firmwareData: Data
    ) async throws -> FirmwareUpdateResponse {
        let environment = APIEnvironment.localDevice(ipAddress: ipAddress, port: port)
        let request = APIRequest(
            environment: environment,
            path: "/firmware/update",
            method: .POST,
            headers: ["Content-Type": "application/octet-stream"],
            body: firmwareData
        )
        let response = try await httpClient.request(request, responseType: FirmwareUpdateResponse.self)
        return response.data
    }
}

// MARK: - Cloud API Service

class CloudAPIService {
    
    static let shared = CloudAPIService()
    private let httpClient = HTTPClient.shared
    private let environment = APIEnvironment.cloud
    
    private init() {}
    
    /// Authenticate user and store token
    func login(email: String, password: String) async throws -> AuthResponse {
        let credentials = LoginCredentials(email: email, password: password)
        let response = try await httpClient.post(
            environment: environment,
            path: "/v1/auth/login",
            body: credentials,
            responseType: AuthResponse.self
        )
        httpClient.authToken = response.data.accessToken
        return response.data
    }
    
    /// Register a new device with the cloud
    func registerDevice(_ device: DeviceRegistration) async throws -> RegisteredDevice {
        let response = try await httpClient.post(
            environment: environment,
            path: "/v1/devices",
            body: device,
            responseType: RegisteredDevice.self
        )
        return response.data
    }
    
    /// Get all registered devices
    func getDevices() async throws -> [RegisteredDevice] {
        let response = try await httpClient.get(
            environment: environment,
            path: "/v1/devices",
            responseType: DeviceListResponse.self
        )
        return response.data.devices
    }
    
    /// Get device telemetry data from cloud
    func getDeviceTelemetry(
        deviceId: String,
        from: Date? = nil,
        to: Date? = nil
    ) async throws -> TelemetryResponse {
        var queryParams: [String: String] = [:]
        let formatter = ISO8601DateFormatter()
        
        if let from = from {
            queryParams["from"] = formatter.string(from: from)
        }
        if let to = to {
            queryParams["to"] = formatter.string(from: to)
        }
        
        let response = try await httpClient.get(
            environment: environment,
            path: "/v1/devices/\(deviceId)/telemetry",
            queryParameters: queryParams.isEmpty ? nil : queryParams,
            responseType: TelemetryResponse.self
        )
        return response.data
    }
    
    /// Send remote command to device via cloud
    func sendRemoteCommand(
        deviceId: String,
        command: DeviceCommand
    ) async throws -> DeviceCommandResponse {
        let response = try await httpClient.post(
            environment: environment,
            path: "/v1/devices/\(deviceId)/commands",
            body: command,
            responseType: DeviceCommandResponse.self
        )
        return response.data
    }
    
    /// Get latest firmware info
    func getLatestFirmware(deviceType: String) async throws -> FirmwareInfo {
        let response = try await httpClient.get(
            environment: environment,
            path: "/v1/firmware/latest",
            queryParameters: ["device_type": deviceType],
            responseType: FirmwareInfo.self
        )
        return response.data
    }
    
    /// Download firmware binary
    func downloadFirmware(firmwareId: String) async throws -> Data {
        let response = try await httpClient.requestData(
            APIRequest(
                environment: environment,
                path: "/v1/firmware/\(firmwareId)/download",
                method: .GET
            )
        )
        return response.data
    }
    
    /// Logout
    func logout() async throws {
        _ = try await httpClient.requestVoid(
            APIRequest(
                environment: environment,
                path: "/v1/auth/logout",
                method: .POST
            )
        )
        httpClient.authToken = nil
    }
}

