// MARK: - AnyCodableValue for flexible JSON values

enum AnyCodableValue: Codable {
    case string(String)
    case int(Int)
    case double(Double)
    case bool(Bool)
    case null
    
    init(from decoder: Decoder) throws {
        let container = try decoder.singleValueContainer()
        
        if container.decodeNil() {
            self = .null
            return
        }
        if let boolValue = try? container.decode(Bool.self) {
            self = .bool(boolValue)
            return
        }
        if let intValue = try? container.decode(Int.self) {
            self = .int(intValue)
            return
        }
        if let doubleValue = try? container.decode(Double.self) {
            self = .double(doubleValue)
            return
        }
        if let stringValue = try? container.decode(String.self) {
            self = .string(stringValue)
            return
        }
        
        throw DecodingError.typeMismatch(
            AnyCodableValue.self,
            DecodingError.Context(codingPath: decoder.codingPath, debugDescription: "Unsupported type")
        )
    }
    
    func encode(to encoder: Encoder) throws {
        var container = encoder.singleValueContainer()
        switch self {
        case .string(let value):
            try container.encode(value)
        case .int(let value):
            try container.encode(value)
        case .double(let value):
            try container.encode(value)
        case .bool(let value):
            try container.encode(value)
        case .null:
            try container.encodeNil()
        }
    }
}

// MARK: - Info.plist Configuration Helper

/*
 Add the following to your Info.plist to allow HTTP connections:
 
 <key>NSAppTransportSecurity</key>
 <dict>
     <!-- Allow insecure HTTP for local network IoT devices -->
     <key>NSAllowsLocalNetworking</key>
     <true/>
     
     <!-- If NSAllowsLocalNetworking is insufficient, use exception domains -->
     <key>NSExceptionDomains</key>
     <dict>
         <!-- Cloud API - enforce HTTPS -->
         <key>api.example.com</key>
         <dict>
             <key>NSExceptionMinimumTLSVersion</key>
             <string>TLSv1.2</string>
             <key>NSIncludesSubdomains</key>
             <true/>
             <key>NSExceptionRequiresForwardSecrecy</key>
             <true/>
         </dict>
     </dict>
     
     <!-- 
     If you need to support arbitrary HTTP connections to any host
     (not recommended for production, but may be needed for legacy devices):
     <key>NSAllowsArbitraryLoads</key>
     <true/>
     -->
 </dict>
 
 <!-- Required for local network access on iOS 14+ -->
 <key>NSLocalNetworkUsageDescription</key>
 <string>This app needs access to your local network to discover and communicate with IoT devices.</string>
 
 <!-- Bonjour services if using mDNS for device discovery -->
 <key>NSBonjourServices</key>
 <array>
     <string>_http._tcp</string>
     <string>_iot._tcp</string>
 </array>
*/

// MARK: - Usage Examples

func exampleUsage() async {
    let cloudAPI = CloudAPIService.shared
    let iotManager = IoTDeviceManager.shared
    
    // --- Cloud API Usage ---
    
    // Login
    do {
        let authResponse = try await cloudAPI.login(
            email: "user@example.com",
            password: "securepassword"
        )
        print("Logged in. Token expires in \(authResponse.expiresIn) seconds")
    } catch {
        print("Login failed: \(error.localizedDescription)")
    }
    
    // Get registered devices from cloud
    do {
        let devices = try await cloudAPI.getDevices()
        for device in devices {
            print("Device: \(device.name) - \(device.online ? "Online" : "Offline")")
        }
    } catch {
        print("Failed to fetch devices: \(error.localizedDescription)")
    }
    
    // --- Local IoT Device Usage ---
    
    // Scan local network for devices
    let discoveredDevices = await iotManager.scanLocalNetwork(subnet: "192.168.1")
    for device in discoveredDevices {
        print("Found device at \(device.ipAddress): \(device.info.name ?? device.info.deviceId)")
    }
    
    // Send command to local device
    do {
        let command = DeviceCommand(
            action: "toggle",
            parameters: ["state": .bool(true)]
        )
        let response = try await iotManager.sendCommand(
            to: "192.168.1.100",
            port: 80,
            command: command
        )
        print("Command result: \(response.success) - \(response.message ?? "")")
    } catch {
        print("Command failed: \(error.localizedDescription)")
    }
    
    // Get device status
    do {
        let status = try await iotManager.getDeviceStatus(ipAddress: "192.168.1.100")
        print("Device temperature: \(status.temperature ?? 0)°C")
    } catch {
        print("Status check failed: \(error.localizedDescription)")
    }
    
    // --- Firmware Update Flow ---
    
    do {
        // Check for latest firmware on cloud
        let firmwareInfo = try await cloudAPI.getLatestFirmware(deviceType: "sensor_v2")
        print("Latest firmware: v\(firmwareInfo.version)")
        
        // Download firmware from cloud
        let firmwareData = try await cloudAPI.downloadFirmware(firmwareId: firmwareInfo.firmwareId)
        print("Downloaded \(firmwareData.count) bytes")
        
        // Push firmware to local device
        let updateResult = try await iotManager.updateFirmware(
            ipAddress: "192.168.1.100",
            firmwareData: firmwareData
        )
        print("Firmware update: \(updateResult.message)")
    } catch {
        print("Firmware update failed: \(error.localizedDescription)")
    }
}